function editDistance(data) {
    const [word1, word2] = data.split('\n');
    function recursiveEditDistance(i, j) {
        if (i === word1.length) return word2.length - j;
        if (j === word2.length) return word1.length - i;
        if (word1[i] === word2[j]) {
            return recursiveEditDistance(i + 1, j + 1);
        }
        const insert = recursiveEditDistance(i, j + 1);
        const deleteOp = recursiveEditDistance(i + 1, j);
        const replace = recursiveEditDistance(i + 1, j + 1);
        return 1 + Math.min(insert, deleteOp, replace);
    }
    return recursiveEditDistance(0, 0);
}

