class Solution {
    public int editDistance(String word1, String word2) {
        return editDistanceHelper(word1, word2, word1.length(), word2.length());
    }
    private int editDistanceHelper(String word1, String word2, int m, int n) {
        if (m == 0) return n; // If word1 is empty, insert all characters of word2
        if (n == 0) return m; // If word2 is empty, remove all characters of word1
        if (word1.charAt(m - 1) == word2.charAt(n - 1)) {
            return editDistanceHelper(word1, word2, m - 1, n - 1); // No operation needed
        }
        int insert = editDistanceHelper(word1, word2, m, n - 1); // Insert
        int delete = editDistanceHelper(word1, word2, m - 1, n); // Delete
        int replace = editDistanceHelper(word1, word2, m - 1, n - 1); // Replace
        return 1 + Math.min(insert, Math.min(delete, replace)); // Return minimum of all operations
    }
}

