package main

import (
    "fmt"
    "math"
)

func editDistance(data string) int {
    words := splitWords(data)
    word1 := words[0]
    word2 := words[1]
    return minEditDistance(word1, word2)
}

func splitWords(data string) []string {
    words := make([]string, 2)
    i := 0
    for j, char := range data {
        if char == ' ' {
            words[i] = data[:j]
            words[1] = data[j+1:]
            break
        }
    }
    return words
}

func minEditDistance(word1 string, word2 string) int {
    if len(word1) == 0 {
        return len(word2)
    }
    if len(word2) == 0 {
        return len(word1)
    }

    if word1[len(word1)-1] == word2[len(word2)-1] {
        return minEditDistance(word1[:len(word1)-1], word2[:len(word2)-1])
    }

    insert := minEditDistance(word1, word2[:len(word2)-1])
    delete := minEditDistance(word1[:len(word1)-1], word2)
    replace := minEditDistance(word1[:len(word1)-1], word2[:len(word2)-1])

    return 1 + min(insert, delete, replace)
}

func min(a, b, c int) int {
    return int(math.Min(float64(a), math.Min(float64(b), float64(c))))
}

